// ── Scryfall support status ───────────────────────────────────────────────

enum ScryfallSupport {
  /// At least one template handles this layout / effect.
  supported,

  /// A template entry exists but has no preview image, or coverage is
  /// limited to specific sub-cases.
  partial,

  /// No template currently supports this layout / effect.
  /// Flag the card in the UI so the user knows it cannot be proxied.
  unsupported,
}

/// Support level for every Scryfall `layout` value.
