// ── Layout compatibility helpers ──────────────────────────────────────────

/// Extracts the template name from an asset path using only the last folder.
/// 'assets/templates/WarpDandy/Samurai/normal.jpg' → 'Samurai'
String templateFolderName(String assetPath) {
  final parts = assetPath.split('/');
  return parts.length >= 2 ? parts[parts.length - 2] : assetPath;
}

/// Maps a Scryfall `layout` value to the template layout key(s) that cover it.
/// A frame is compatible when [TemplateInfo.layouts] contains at least one of
/// the returned keys.
Set<String> templateLayoutKeys(String? scryfallLayout) {
  switch (scryfallLayout) {
    case 'normal':
    case 'flip':
      return const {'normal'};
    case 'token':
    case 'emblem':
      return const {'token', 'normal'};
    case 'transform':
      return const {'transform_front', 'transform_back'};
    case 'modal_dfc':
      return const {'mdfc_front', 'mdfc_back'};
    case 'saga':        return const {'saga'};
    case 'leveler':     return const {'leveler'};
    case 'adventure':   return const {'adventure'};
    case 'class':       return const {'class'};
    case 'battle':      return const {'battle'};
    case 'planeswalker':return const {'planeswalker'};
    case 'mutate':      return const {'mutate'};
    case 'prototype':   return const {'prototype'};
    case 'split':       return const {'split'};
    default:            return const {'normal'};
  }
}

/// Returns true if [info] supports every layout in [scryfallLayouts].
/// Pass an empty set to consider all frames compatible.
bool frameCompatible(TemplateInfo info, Set<String> scryfallLayouts) {
  if (scryfallLayouts.isEmpty) return true;
  return scryfallLayouts.every((sl) {
    final keys = templateLayoutKeys(sl);
    return keys.any((k) => info.layouts.containsKey(k));
  });
}

// ── Template info ─────────────────────────────────────────────────────────

class TemplateInfo {
  final String author;

  /// layout name → asset path
  final Map<String, String> layouts;

  const TemplateInfo({required this.author, required this.layouts});
}
